import json
import pymysql
from decimal import Decimal

def lambda_handler(event, context):
    # Get search parameters from API Gateway event
    query = event['queryStringParameters']
    page = int(event['pathParameters']['page'])
    limit = int(event['pathParameters']['limit'])

    # Connect to RDS MySQL database
    conn = pymysql.connect(host='your-rds-instance-endpoint', user='your-username', password='your-password', db='your-database')
    cursor = conn.cursor()

    # Build SQL query dynamically based on search parameters
    sql = 'SELECT * FROM products WHERE 1=1'
    if query:
        for key, value in query.items():
            if key == 'name':
                sql += f" AND name LIKE '%{value}%'"
            elif key == 'price':
                sql += f" AND price >= {Decimal(value)}"
            elif key == 'category':
                sql += f" AND category = '{value}'"
    sql += f" LIMIT {limit} OFFSET {page * limit}"

    # Execute SQL query and return results
    cursor.execute(sql)
    results = cursor.fetchall()
    conn.close()
    return {'results': [dict(zip([col[0] for col in cursor.description], row)) for row in results]}